allow:
Bash(/tmp/search_claude2.ps1 << 'PSEOF'
$userHome = [Environment]::GetFolderPath\('UserProfile'\)
$claudeDir = Join-Path $userHome '.claude'

Write-Output "=== SEARCHING FOR CATEGORY RENEWAL v4 ==="

$files = Get-ChildItem -Path $claudeDir -Filter '*.jsonl' -Recurse
foreach \($file in $files\) {
    $lines = Get-Content $file.FullName -Encoding UTF8
    for \($i = 0; $i -lt $lines.Count; $i++\) {
        if \($lines[$i] -match '리뉴얼 v4|5개 카테고리|14개.*서브|me.*love.*career.*year.*future'\) {
            Write-Output "FOUND in $\($file.Name\) at line $i"
        }
    }
}
PSEOF)
